import React, { useState, useEffect, useMemo } from 'react';
import { Container, Typography, Toolbar, makeStyles, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Box, Button, Modal, Dialog, DialogTitle, DialogContent, DialogContentText, TextField } from '@material-ui/core'
import { StudentColumns } from './StudentColumns';
import { DeleteForever, EditRounded, Search } from '@material-ui/icons';
import SearchFilter from './Search'
import { CheckBox } from './CheckBox';
import axios from 'axios'
import { useTable, useGlobalFilter, useRowSelect } from 'react-table';

const useStyle = makeStyles(theme => {
  return {
    mainRoot: {
      '& .MuiTableCell-stickyHeader': {
        backgroundColor: '#333',
        border: '#333',
        color: '#f9f9f9'
      }
    },
    root: {
      '& .MuiTableCell-root': {
        border: '1px solid #dfdfdf'
      },
      '& .MuiTableRow-root': {
        '&:hover': {
          backgroundColor: '#dfdfdf'
        },
        '&:nth-child(even)': {
          backgroundColor: '#f4f4f4',
          '&:hover': {
            backgroundColor: '#dfdfdf'
          }
        }
      }
    },
    container: {
      maxHeight: 448,
    },
    header: {
      padding: theme.spacing(1)
    },
    search: {
      position: 'relative',
      borderRadius: theme.shape.borderRadius,
      backgroundColor: 'rgba(0,0,0,0.1)',
      '&:hover': {
        backgroundColor: 'rgba(0,0,0,0.25)',
      },
      '& .Mui-focus': {
        backgroundColor: 'rgba(0,0,0,0.25)',
      },
      marginRight: theme.spacing(2),
      marginLeft: 0,
      width: '100%',
      [theme.breakpoints.up('sm')]: {
        marginLeft: theme.spacing(3),
        width: 'auto',
      },
    },
    searchIcon: {
      padding: theme.spacing(0, 2),
      height: '100%',
      position: 'absolute',
      pointerEvents: 'none',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
    },
    divider: {
      backgroundColor: '#222'
    }
  }
})



export default function StudentTable() {

  const classes = useStyle();


  const [students, setStudents] = useState([]);
  function showStudents() {
    axios.get('http://localhost:80/api/studentsTable.php')
      .then((response) => {
        setStudents(response.data);
      })
      .catch(err => console.log(err))
  };
  useEffect(() => {
    showStudents();
  }, []);


  const columns = useMemo(() => StudentColumns, []);
  const data = useMemo(() => students, [students]);

  

  const tableHooks = (hooks) => {
    hooks.visibleColumns.push((columns) => [
      ...columns,
      {
        id: 'Edit',
        Header: 'Edit',
        Cell: ({ row }) => (
          <Button variant='contained' color='secondary' disableElevation onClick={handleOpen} >
            <EditRounded />
          </Button>
        ),
      },
      {
        id: 'Delete',
        Header: 'Delete',
        Cell: ({ row }) => (
          <Button variant='contained' color='secondary' disableElevation onClick={() => {
            axios.post('http://localhost:80/api/removeStudent.php', row.values.id)
            .then(response => {
              console.log(response.data);
              showStudents();
            })
            }} >
            <DeleteForever />
          </Button>
        ),
      },
    ])
  }

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
    state,
    setGlobalFilter
  } = useTable({
    columns,
    data,
  },
    tableHooks,
    useGlobalFilter,
  )

  const [editModal, setEditModal] = useState(false);

  const handleOpen = () => {
    setEditModal(true)
  }

  const handleClose = () => {
    setEditModal(false)
  }


  const { globalFilter } = state

  return (
    <>
      <Box className={classes.mainRoot}>
        <div>
          
    <Dialog
        open={editModal}
        onClose={handleClose}
        aria-labelledby="simple-modal-title"
        aria-describedby="simple-modal-description"
      >
        <DialogTitle>
            Edit Data
        </DialogTitle>
        <DialogContent>
        <form >

        
<TextField variant='outlined' placeholder='First Name'  type="text" name='firstName' fullWidth/>
<br /><br />


<TextField variant='outlined' placeholder='Middle Name'  type="text" name='middleName'  fullWidth/>
<br /><br />


<TextField variant='outlined' placeholder='Last Name'  type="text" name='lastName' fullWidth/>
<br /><br />


<TextField variant='outlined' placeholder='Student ID'  type="text" name='studentID'  fullWidth/>
<br /><br />


<TextField variant='outlined' placeholder='College'  type="text" name='college' fullWidth/>
<br /><br />


<TextField variant='outlined' placeholder='Course'  type="text" name='course' fullWidth/>
<br /><br />


<TextField variant='outlined' placeholder='Password'  type="password" name='password' fullWidth/>
<br /><br />


<Button fullWidth type='submit' name='submit' variant='contained' color='secondary' >Register</Button>

</form>
        </DialogContent>
      </Dialog>
        </div>
        <Container className={classes.root}>
          <Paper variant='outlined'>
            <div className={classes.header}>
              <Toolbar>
                  <Typography variant='h4'>
                    Student List
                  </Typography>
                <div className={classes.search}>
                  <div className={classes.searchIcon}>
                    <Search />
                  </div>
                  <SearchFilter filter={globalFilter} setFilter={setGlobalFilter} />
                </div>
              </Toolbar>
            </div>
            <TableContainer className={classes.container}>
              <Table {...getTableProps} size="small" stickyHeader>
                <TableHead>
                  {headerGroups.map((headerGroup) => (
                    <TableRow {...headerGroup.getHeaderGroupProps()}>
                      {headerGroup.headers.map((column) => (
                        <TableCell {...column.getHeaderProps()}>
                          {column.render('Header')}
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </TableHead>
                <TableBody {...getTableBodyProps}>
                  {rows.map((row) => {
                    prepareRow(row)
                    return (
                      <TableRow {...row.getRowProps()}>
                        {row.cells.map((cell) => {
                          return (
                            <TableCell {...cell.getCellProps()}>
                              {cell.render('Cell')}
                            </TableCell>
                          )
                        })}
                      </TableRow>
                    )
                  })}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        </Container>
      </Box>
    </>
  );
}
